  1→<!DOCTYPE html>
  2→<html lang="en">
  3→<head>
  4→<meta charset="UTF-8">
  5→<meta name="viewport" content="width=device-width, initial-scale=1.0">
  6→<title>Chess Demo</title>
  7→<style>
  8→  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
  9→
 10→  body {
 11→    min-height: 100vh;
 12→    display: flex;
 13→    flex-direction: column;
 14→    justify-content: center;
 15→    align-items: center;
 16→    background: #1a1a2e;
 17→    font-family: system-ui, -apple-system, sans-serif;
 18→  }
 19→
 20→  .board-container {
 21→    display: inline-grid;
 22→    grid-template-columns: 2rem repeat(8, 1fr);
 23→    grid-template-rows: repeat(8, 1fr) 2rem;
 24→    max-width: min(90vw, 90vh);
 25→    aspect-ratio: 1;
 26→    width: 560px;
 27→    border: 4px solid #16213e;
 28→    border-radius: 6px;
 29→    overflow: hidden;
 30→    box-shadow: 0 8px 32px rgba(0,0,0,.5);
 31→  }
 32→
 33→  .rank-label {
 34→    display: flex;
 35→    align-items: center;
 36→    justify-content: center;
 37→    background: #16213e;
 38→    color: #a0a0b0;
 39→    font-size: 0.85rem;
 40→    font-weight: 600;
 41→    width: 2rem;
 42→  }
 43→
 44→  .file-label {
 45→    display: flex;
 46→    align-items: center;
 47→    justify-content: center;
 48→    background: #16213e;
 49→    color: #a0a0b0;
 50→    font-size: 0.85rem;
 51→    font-weight: 600;
 52→    height: 2rem;
 53→  }
 54→
 55→  .corner {
 56→    background: #16213e;
 57→  }
 58→
 59→  .square {
 60→    display: flex;
 61→    align-items: center;
 62→    justify-content: center;
 63→    font-size: clamp(1.5rem, 5vw, 3.2rem);
 64→    cursor: pointer;
 65→    user-select: none;
 66→    transition: background-color 0.15s;
 67→    aspect-ratio: 1;
 68→  }
 69→
 70→  .square.light { background: #e8dcc8; }
 71→  .square.dark  { background: #7b6b4f; }
 72→  .square:hover { filter: brightness(1.12); }
 73→
 74→  .square.selected { background: #f6e96b !important; }
 75→  .square.valid-move { position: relative; }
 76→  .square.valid-move::after {
 77→    content: '';
 78→    position: absolute;
 79→    width: 30%;
 80→    height: 30%;
 81→    background: rgba(0, 0, 0, 0.25);
 82→    border-radius: 50%;
 83→    pointer-events: none;
 84→  }
 85→  .square.valid-move.has-enemy::after {
 86→    width: 85%;
 87→    height: 85%;
 88→    background: transparent;
 89→    border: 5px solid rgba(0, 0, 0, 0.25);
 90→    border-radius: 50%;
 91→  }
 92→
 93→  .turn-indicator {
 94→    text-align: center;
 95→    color: #a0a0b0;
 96→    font-size: 1.1rem;
 97→    margin-top: 1rem;
 98→    font-weight: 600;
 99→  }
100→</style>
101→</head>
102→<body>
103→
104→<div class="board-container" id="board"></div>
105→<div class="turn-indicator" id="turn">White's turn</div>
106→
107→<script>
108→const PIECES = {
109→  K: { type: 'king',   color: 'white', symbol: '\u2654' },
110→  Q: { type: 'queen',  color: 'white', symbol: '\u2655' },
111→  R: { type: 'rook',   color: 'white', symbol: '\u2656' },
112→  B: { type: 'bishop', color: 'white', symbol: '\u2657' },
113→  N: { type: 'knight', color: 'white', symbol: '\u2658' },
114→  P: { type: 'pawn',   color: 'white', symbol: '\u2659' },
115→  k: { type: 'king',   color: 'black', symbol: '\u265A' },
116→  q: { type: 'queen',  color: 'black', symbol: '\u265B' },
117→  r: { type: 'rook',   color: 'black', symbol: '\u265C' },
118→  b: { type: 'bishop', color: 'black', symbol: '\u265D' },
119→  n: { type: 'knight', color: 'black', symbol: '\u265E' },
120→  p: { type: 'pawn',   color: 'black', symbol: '\u265F' },
121→};
122→
123→function makePiece(key) {
124→  if (!key) return null;
125→  const p = PIECES[key];
126→  return { type: p.type, color: p.color, symbol: p.symbol };
127→}
128→
129→// Board state: board[row][col], row 0 = rank 8 (top)
130→const INITIAL = [
131→  ['r','n','b','q','k','b','n','r'],
132→  ['p','p','p','p','p','p','p','p'],
133→  ['' ,'' ,'' ,'' ,'' ,'' ,'' ,''],
134→  ['' ,'' ,'' ,'' ,'' ,'' ,'' ,''],
135→  ['' ,'' ,'' ,'' ,'' ,'' ,'' ,''],
136→  ['' ,'' ,'' ,'' ,'' ,'' ,'' ,''],
137→  ['P','P','P','P','P','P','P','P'],
138→  ['R','N','B','Q','K','B','N','R'],
139→];
140→
141→const boardState = INITIAL.map(row => row.map(makePiece));
142→
143→const FILES = ['a','b','c','d','e','f','g','h'];
144→const container = document.getElementById('board');
145→const turnIndicator = document.getElementById('turn');
146→
147→let currentTurn = 'white';
148→let selectedSquare = null; // { row, col }
149→let validMoves = [];       // [{ row, col }, ...]
150→
151→function inBounds(r, c) {
152→  return r >= 0 && r < 8 && c >= 0 && c < 8;
153→}
154→
155→function slidingMoves(row, col, directions) {
156→  const piece = boardState[row][col];
157→  const moves = [];
158→  for (const [dr, dc] of directions) {
159→    let r = row + dr, c = col + dc;
160→    while (inBounds(r, c)) {
161→      const target = boardState[r][c];
162→      if (!target) {
163→        moves.push({ row: r, col: c });
164→      } else {
165→        if (target.color !== piece.color) moves.push({ row: r, col: c });
166→        break;
167→      }
168→      r += dr;
169→      c += dc;
170→    }
171→  }
172→  return moves;
173→}
174→
175→function getValidMoves(piece, row, col) {
176→  const moves = [];
177→
178→  if (piece.type === 'pawn') {
179→    const dir = piece.color === 'white' ? -1 : 1;
180→    const startRow = piece.color === 'white' ? 6 : 1;
181→    // Forward one
182→    if (inBounds(row + dir, col) && !boardState[row + dir][col]) {
183→      moves.push({ row: row + dir, col });
184→      // Forward two from start
185→      if (row === startRow && !boardState[row + 2 * dir][col]) {
186→        moves.push({ row: row + 2 * dir, col });
187→      }
188→    }
189→    // Diagonal captures
190→    for (const dc of [-1, 1]) {
191→      const nr = row + dir, nc = col + dc;
192→      if (inBounds(nr, nc) && boardState[nr][nc] && boardState[nr][nc].color !== piece.color) {
193→        moves.push({ row: nr, col: nc });
194→      }
195→    }
196→  }
197→
198→  if (piece.type === 'rook' || piece.type === 'queen') {
199→    moves.push(...slidingMoves(row, col, [[1,0],[-1,0],[0,1],[0,-1]]));
200→  }
201→
202→  if (piece.type === 'bishop' || piece.type === 'queen') {
203→    moves.push(...slidingMoves(row, col, [[1,1],[1,-1],[-1,1],[-1,-1]]));
204→  }
205→
206→  if (piece.type === 'knight') {
207→    for (const [dr, dc] of [[2,1],[2,-1],[-2,1],[-2,-1],[1,2],[1,-2],[-1,2],[-1,-2]]) {
208→      const nr = row + dr, nc = col + dc;
209→      if (inBounds(nr, nc)) {
210→        const target = boardState[nr][nc];
211→        if (!target || target.color !== piece.color) moves.push({ row: nr, col: nc });
212→      }
213→    }
214→  }
215→
216→  if (piece.type === 'king') {
217→    for (let dr = -1; dr <= 1; dr++) {
218→      for (let dc = -1; dc <= 1; dc++) {
219→        if (dr === 0 && dc === 0) continue;
220→        const nr = row + dr, nc = col + dc;
221→        if (inBounds(nr, nc)) {
222→          const target = boardState[nr][nc];
223→          if (!target || target.color !== piece.color) moves.push({ row: nr, col: nc });
224→        }
225→      }
226→    }
227→  }
228→
229→  return moves;
230→}
231→
232→function getSquareEl(row, col) {
233→  return container.querySelector(`.square[data-row="${row}"][data-col="${col}"]`);
234→}
235→
236→function clearHighlights() {
237→  container.querySelectorAll('.square.selected, .square.valid-move').forEach(sq => {
238→    sq.classList.remove('selected', 'valid-move', 'has-enemy');
239→  });
240→}
241→
242→function applyHighlights() {
243→  if (!selectedSquare) return;
244→  getSquareEl(selectedSquare.row, selectedSquare.col).classList.add('selected');
245→  for (const m of validMoves) {
246→    const el = getSquareEl(m.row, m.col);
247→    el.classList.add('valid-move');
248→    if (boardState[m.row][m.col]) el.classList.add('has-enemy');
249→  }
250→}
251→
252→function movePiece(fromRow, fromCol, toRow, toCol) {
253→  boardState[toRow][toCol] = boardState[fromRow][fromCol];
254→  boardState[fromRow][fromCol] = null;
255→
256→  // Update DOM
257→  const fromEl = getSquareEl(fromRow, fromCol);
258→  const toEl = getSquareEl(toRow, toCol);
259→  fromEl.textContent = '';
260→  toEl.textContent = boardState[toRow][toCol].symbol;
261→
262→  // Switch turn
263→  currentTurn = currentTurn === 'white' ? 'black' : 'white';
264→  turnIndicator.textContent = currentTurn === 'white' ? "White's turn" : "Black's turn";
265→}
266→
267→function handleClick(row, col) {
268→  const piece = boardState[row][col];
269→
270→  // If a piece is already selected
271→  if (selectedSquare) {
272→    // Check if clicking a valid move destination
273→    const isValid = validMoves.some(m => m.row === row && m.col === col);
274→    if (isValid) {
275→      clearHighlights();
276→      movePiece(selectedSquare.row, selectedSquare.col, row, col);
277→      selectedSquare = null;
278→      validMoves = [];
279→      return;
280→    }
281→
282→    // Deselect current piece
283→    const prevRow = selectedSquare.row;
284→    const prevCol = selectedSquare.col;
285→    clearHighlights();
286→    selectedSquare = null;
287→    validMoves = [];
288→
289→    // If clicked a different own piece, select it instead
290→    if (piece && piece.color === currentTurn && !(row === prevRow && col === prevCol)) {
291→      // fall through to selection below
292→    } else {
293→      return;
294→    }
295→  }
296→
297→  // Select a piece of the current player
298→  if (piece && piece.color === currentTurn) {
299→    const moves = getValidMoves(piece, row, col);
300→    if (moves.length > 0) {
301→      selectedSquare = { row, col };
302→      validMoves = moves;
303→      applyHighlights();
304→    }
305→  }
306→}
307→
308→// Build the board
309→for (let row = 0; row < 8; row++) {
310→  const rl = document.createElement('div');
311→  rl.className = 'rank-label';
312→  rl.textContent = 8 - row;
313→  container.appendChild(rl);
314→
315→  for (let col = 0; col < 8; col++) {
316→    const sq = document.createElement('div');
317→    const isLight = (row + col) % 2 === 0;
318→    sq.className = 'square ' + (isLight ? 'light' : 'dark');
319→    sq.dataset.row = row;
320→    sq.dataset.col = col;
321→
322→    const piece = boardState[row][col];
323→    if (piece) sq.textContent = piece.symbol;
324→
325→    sq.addEventListener('click', () => handleClick(row, col));
326→
327→    container.appendChild(sq);
328→  }
329→}
330→
331→// File labels row
332→const corner = document.createElement('div');
333→corner.className = 'corner';
334→container.appendChild(corner);
335→
336→for (const f of FILES) {
337→  const fl = document.createElement('div');
338→  fl.className = 'file-label';
339→  fl.textContent = f;
340→  container.appendChild(fl);
341→}
342→</script>
343→</body>
344→</html>
